import{_ as d,o as e,i as o,aB as a}from"./chunks/framework._ZAOES46.js";const b=JSON.parse('{"title":"FaButton 按钮","description":"","frontmatter":{},"headers":[],"relativePath":"components/basic/FaButton.md","filePath":"components/basic/FaButton.md"}'),l={name:"components/basic/FaButton.md"};function i(r,t,c,n,s,h){return e(),o("div",null,[...t[0]||(t[0]=[a('<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /components/basic/FaButton.md for this page in Markdown format</div><h1 id="fabutton-按钮" tabindex="-1">FaButton 按钮 <a class="header-anchor" href="#fabutton-按钮" aria-label="Permalink to “FaButton 按钮”">​</a></h1><p>基础按钮组件，支持多种样式变体和尺寸，内置加载状态支持。</p><h2 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to “使用场景”">​</a></h2><ul><li>表单提交按钮</li><li>操作触发按钮（新增、编辑、删除）</li><li>导航链接按钮</li><li>工具栏操作按钮</li><li>对话框/抽屉底部操作按钮</li></ul><h2 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to “Props”">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>类型</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>variant</code></td><td><code>&#39;default&#39; | &#39;destructive&#39; | &#39;outline&#39; | &#39;secondary&#39; | &#39;ghost&#39; | &#39;link&#39; | &#39;expand&#39;</code></td><td><code>&#39;default&#39;</code></td><td>按钮样式变体</td></tr><tr><td><code>size</code></td><td><code>&#39;default&#39; | &#39;sm&#39; | &#39;lg&#39; | &#39;icon&#39; | &#39;icon-sm&#39; | &#39;icon-lg&#39;</code></td><td><code>&#39;default&#39;</code></td><td>按钮尺寸</td></tr><tr><td><code>disabled</code></td><td><code>boolean</code></td><td><code>false</code></td><td>是否禁用</td></tr><tr><td><code>loading</code></td><td><code>boolean</code></td><td><code>false</code></td><td>是否显示加载状态</td></tr><tr><td><code>class</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>-</td><td>自定义 CSS 类</td></tr></tbody></table><h2 id="slots" tabindex="-1">Slots <a class="header-anchor" href="#slots" aria-label="Permalink to “Slots”">​</a></h2><table tabindex="0"><thead><tr><th>名称</th><th>说明</th></tr></thead><tbody><tr><td><code>default</code></td><td>按钮内容（图标、文字等）</td></tr></tbody></table><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h2><ol><li><strong>loading 状态</strong>：设置 <code>loading</code> 为 <code>true</code> 时，按钮会自动显示旋转加载图标并禁用点击</li><li><strong>icon 尺寸</strong>： <ul><li><code>size=&quot;icon&quot;</code>：正方形按钮 (36px)，适合放置纯图标</li><li><code>size=&quot;icon-sm&quot;</code>：小号正方形按钮 (32px)</li><li><code>size=&quot;icon-lg&quot;</code>：大号正方形按钮 (40px)</li></ul></li><li><strong>变体选择</strong>： <ul><li><code>default</code>：主操作按钮</li><li><code>secondary</code>：次要操作</li><li><code>destructive</code>：删除、危险操作</li><li><code>outline</code>：边框样式，用于低优先级操作</li><li><code>ghost</code>：幽灵按钮，用于更次要的操作</li><li><code>link</code>：链接样式</li><li><code>expand</code>：展开动画效果按钮</li></ul></li></ol><h2 id="fabuttongroup-按钮组" tabindex="-1">FaButtonGroup 按钮组 <a class="header-anchor" href="#fabuttongroup-按钮组" aria-label="Permalink to “FaButtonGroup 按钮组”">​</a></h2><p>将多个按钮组合在一起的容器组件，支持水平/垂直排列和分割线。</p><h2 id="使用场景-1" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景-1" aria-label="Permalink to “使用场景”">​</a></h2><ul><li>将多个按钮组合在一起的容器组件，支持水平/垂直排列和分割线。</li><li>常见用法：垂直排列、带分割线、工具栏按钮组、垂直菜单。</li></ul><h2 id="props-1" tabindex="-1">Props <a class="header-anchor" href="#props-1" aria-label="Permalink to “Props”">​</a></h2><table tabindex="0"><thead><tr><th>参数</th><th>说明</th><th>类型</th><th>默认值</th></tr></thead><tbody><tr><td>orientation</td><td>排列方向</td><td><code>&#39;horizontal&#39; | &#39;vertical&#39;</code></td><td><code>&#39;horizontal&#39;</code></td></tr><tr><td>separator</td><td>是否显示分割线</td><td><code>boolean</code></td><td><code>false</code></td></tr><tr><td>class</td><td>自定义类名</td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td><code>undefined</code></td></tr></tbody></table><h2 id="slots-1" tabindex="-1">Slots <a class="header-anchor" href="#slots-1" aria-label="Permalink to “Slots”">​</a></h2><table tabindex="0"><thead><tr><th>名称</th><th>说明</th></tr></thead><tbody><tr><td>default</td><td>默认插槽，放置 FaButton 组件</td></tr></tbody></table><h2 id="注意事项-1" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项-1" aria-label="Permalink to “注意事项”">​</a></h2><ul><li>无特殊限制，建议按示例中的受控方式接入，并结合业务容器尺寸验证最终展示效果。</li></ul>',21)])])}const p=d(l,[["render",i]]);export{b as __pageData,p as default};
